"use client";
import { useState } from "react";
import { FileText, CheckCircle, AlertTriangle, Edit3, Download, Lock, Unlock, ArrowRight, Cpu } from "lucide-react";
import { MORNING_BRIEFING, generateAIAssessment } from "../lib/agent";

export default function BriefingPanel({ events, agentDone, approved, onApprove, onVerdict }) {
  const [editingSection, setEditingSection] = useState(null);
  const [overrides, setOverrides] = useState({});
  const [activeSection, setActiveSection] = useState("summary");

  if (!agentDone) {
    return (
      <div className="section-card flex flex-col items-center justify-center py-16 text-center">
        <Cpu size={32} className="mb-4 animate-pulse-amber" style={{ color: "var(--brand-amber)" }} />
        <h3 className="text-base font-semibold mb-2" style={{ color: "var(--text-primary)" }}>Investigation Required</h3>
        <p className="text-sm max-w-md" style={{ color: "var(--text-muted)" }}>
          Run the AI investigation first. The morning briefing will be generated automatically once the agent completes its analysis.
        </p>
      </div>
    );
  }

  const sections = Object.entries(MORNING_BRIEFING.sections);
  const reviewedCount = events.filter(e => e.userVerdict !== null).length;
  const pendingCount = events.length - reviewedCount;
  const escalations = events.filter(e => e.aiAssessment?.verdict === "escalate");

  const getContent = (key) => overrides[key] ?? MORNING_BRIEFING.sections[key]?.content ?? "";

  return (
    <div className="grid grid-cols-1 xl:grid-cols-3 gap-5">
      {/* Left: Section nav + status */}
      <div className="flex flex-col gap-4">
        {/* Header card */}
        <div className="section-card">
          <div className="flex items-center gap-2 mb-3">
            <FileText size={16} style={{ color: "var(--brand-amber)" }} />
            <h2 className="text-sm font-semibold" style={{ color: "var(--text-primary)" }}>Morning Briefing</h2>
          </div>
          <div className="space-y-1 mb-4">
            <div className="text-xs" style={{ color: "var(--text-muted)" }}>
              <span style={{ color: "var(--text-secondary)" }}>For: </span>{MORNING_BRIEFING.preparedFor}
            </div>
            <div className="text-xs" style={{ color: "var(--text-muted)" }}>
              <span style={{ color: "var(--text-secondary)" }}>Generated: </span>{MORNING_BRIEFING.generatedAt}
            </div>
            <div className="text-xs" style={{ color: "var(--text-muted)" }}>
              <span style={{ color: "var(--text-secondary)" }}>By: </span>{MORNING_BRIEFING.preparedBy}
            </div>
          </div>

          {/* Review status */}
          <div className="rounded-lg p-3 mb-3"
            style={{ background: "var(--surface-0)", border: "1px solid var(--border-subtle)" }}>
            <div className="text-xs font-medium mb-2" style={{ color: "var(--text-secondary)" }}>Maya's Review Status</div>
            <div className="flex items-center justify-between mb-1.5">
              <span className="text-xs" style={{ color: "var(--text-muted)" }}>Events reviewed</span>
              <span className="text-xs font-medium" style={{ color: reviewedCount === events.length ? "var(--brand-green)" : "var(--brand-amber)" }}>
                {reviewedCount} / {events.length}
              </span>
            </div>
            <div className="h-1.5 rounded-full mb-2" style={{ background: "var(--surface-3)" }}>
              <div className="h-full rounded-full transition-all"
                style={{ width: `${(reviewedCount / events.length) * 100}%`, background: "var(--brand-green)" }} />
            </div>
            {pendingCount > 0 && (
              <div className="text-xs" style={{ color: "var(--brand-amber)" }}>
                ⚠ {pendingCount} events still pending review
              </div>
            )}
          </div>

          {/* Approve button */}
          {!approved ? (
            <button onClick={onApprove}
              disabled={pendingCount > 0}
              className="w-full py-2.5 rounded-lg text-sm font-semibold flex items-center justify-center gap-2 transition-all"
              style={{
                background: pendingCount > 0 ? "rgba(255,255,255,0.03)" : "rgba(16,185,129,0.15)",
                border: `1px solid ${pendingCount > 0 ? "var(--border-subtle)" : "rgba(16,185,129,0.35)"}`,
                color: pendingCount > 0 ? "var(--text-muted)" : "#6ee7b7",
                cursor: pendingCount > 0 ? "not-allowed" : "pointer",
              }}>
              {pendingCount > 0 ? (
                <><Lock size={14} /> Review All Events First</>
              ) : (
                <><CheckCircle size={14} /> Approve for Briefing</>
              )}
            </button>
          ) : (
            <div className="w-full py-2.5 rounded-lg text-sm font-semibold flex items-center justify-center gap-2"
              style={{ background: "rgba(16,185,129,0.12)", border: "1px solid rgba(16,185,129,0.3)", color: "#6ee7b7" }}>
              <CheckCircle size={14} /> Briefing Approved
            </div>
          )}
        </div>

        {/* Section nav */}
        <div className="section-card">
          <div className="text-xs font-medium mb-3" style={{ color: "var(--text-secondary)" }}>Sections</div>
          <div className="space-y-1">
            {sections.map(([key, section]) => (
              <button key={key} onClick={() => setActiveSection(key)}
                className="w-full text-left px-3 py-2 rounded-lg text-xs transition-all flex items-center gap-2"
                style={{
                  background: activeSection === key ? "rgba(245,158,11,0.1)" : "transparent",
                  border: `1px solid ${activeSection === key ? "rgba(245,158,11,0.25)" : "transparent"}`,
                  color: activeSection === key ? "var(--brand-amber)" : "var(--text-muted)",
                }}>
                <ArrowRight size={11} />
                {section.title}
                {overrides[key] && <span className="ml-auto text-xs px-1 rounded" style={{ background: "rgba(245,158,11,0.1)", color: "var(--brand-amber)" }}>Edited</span>}
              </button>
            ))}
          </div>
        </div>

        {/* Escalation summary */}
        <div className="section-card">
          <div className="text-xs font-medium mb-3 flex items-center gap-2" style={{ color: "var(--text-secondary)" }}>
            <AlertTriangle size={12} style={{ color: "var(--brand-red)" }} /> Escalations
          </div>
          {escalations.map(event => (
            <div key={event.id} className="mb-2 rounded-lg px-3 py-2"
              style={{ background: "rgba(239,68,68,0.06)", border: "1px solid rgba(239,68,68,0.2)" }}>
              <div className="text-xs font-medium" style={{ color: "#fca5a5" }}>{event.title}</div>
              <div className="text-xs mt-0.5" style={{ color: "var(--text-muted)" }}>{event.time} · {event.location}</div>
              {event.userVerdict && (
                <div className="text-xs mt-1" style={{ color: event.userVerdict === "approved" ? "#6ee7b7" : "#fca5a5" }}>
                  Maya: {event.userVerdict === "approved" ? "✓ Approved escalation" : "✕ Challenged"}
                </div>
              )}
            </div>
          ))}
          {escalations.length === 0 && (
            <div className="text-xs" style={{ color: "var(--text-muted)" }}>No escalations flagged</div>
          )}
        </div>
      </div>

      {/* Right: Active section content */}
      <div className="xl:col-span-2">
        {sections.map(([key, section]) =>
          activeSection === key ? (
            <BriefingSection
              key={key}
              sectionKey={key}
              section={section}
              content={getContent(key)}
              editing={editingSection === key}
              approved={approved}
              onEdit={() => setEditingSection(key)}
              onSave={(newContent) => { setOverrides(prev => ({ ...prev, [key]: newContent })); setEditingSection(null); }}
              onCancel={() => setEditingSection(null)}
            />
          ) : null
        )}
      </div>
    </div>
  );
}

function BriefingSection({ sectionKey, section, content, editing, approved, onEdit, onSave, onCancel }) {
  const [draft, setDraft] = useState(content);

  const SECTION_COLORS = {
    summary: "#3b82f6",
    harmless: "#10b981",
    escalation: "#ef4444",
    drone: "#8b5cf6",
    followup: "#f59e0b",
    actions: "#10b981",
  };
  const color = SECTION_COLORS[sectionKey] || "#8b949e";

  return (
    <div className="section-card animate-fade-in">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <div className="w-2 h-8 rounded-full" style={{ background: color }} />
          <h3 className="text-base font-semibold" style={{ color: "var(--text-primary)" }}>{section.title}</h3>
        </div>
        {!approved && !editing && (
          <button onClick={onEdit}
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs transition-all"
            style={{ background: "var(--surface-2)", border: "1px solid var(--border-subtle)", color: "var(--text-secondary)" }}>
            <Edit3 size={12} /> Edit
          </button>
        )}
        {approved && (
          <div className="flex items-center gap-1 text-xs" style={{ color: "#6ee7b7" }}>
            <Lock size={11} /> Approved
          </div>
        )}
      </div>

      {editing ? (
        <div>
          <textarea
            value={draft}
            onChange={e => setDraft(e.target.value)}
            rows={12}
            className="w-full rounded-lg p-3 text-sm resize-none focus:outline-none"
            style={{
              background: "var(--surface-0)",
              border: "1px solid rgba(245,158,11,0.3)",
              color: "var(--text-secondary)",
              fontFamily: "var(--font-geist)",
              lineHeight: 1.7,
            }}
          />
          <div className="flex gap-2 mt-3">
            <button onClick={() => onSave(draft)}
              className="px-4 py-2 rounded-lg text-xs font-medium"
              style={{ background: "rgba(16,185,129,0.15)", border: "1px solid rgba(16,185,129,0.3)", color: "#6ee7b7" }}>
              Save Changes
            </button>
            <button onClick={onCancel}
              className="px-4 py-2 rounded-lg text-xs font-medium"
              style={{ background: "var(--surface-2)", border: "1px solid var(--border-subtle)", color: "var(--text-muted)" }}>
              Cancel
            </button>
          </div>
        </div>
      ) : (
        <div>
          <div className="rounded-lg p-4"
            style={{ background: "var(--surface-0)", border: "1px solid var(--border-subtle)" }}>
            {content.split("\n\n").map((para, i) => (
              <p key={i} className="text-sm leading-relaxed mb-3 last:mb-0" style={{ color: "var(--text-secondary)" }}>
                {para.split("\n").map((line, j) => (
                  <span key={j}>
                    {line}
                    {j < para.split("\n").length - 1 && <br />}
                  </span>
                ))}
              </p>
            ))}
          </div>

          <div className="flex items-center gap-2 mt-3 text-xs" style={{ color: "var(--text-muted)" }}>
            <Cpu size={11} style={{ color: "var(--brand-amber)" }} />
            <span>Generated by 6:10 Assistant</span>
            <span>·</span>
            <span>Review and edit before sharing with leadership</span>
          </div>
        </div>
      )}
    </div>
  );
}
